<?php
$pageTitle='Supplier Contracts';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('supplier_contracts');
$pdo=getDB();$suppliers=$pdo->query('SELECT id,supplier_code,company_name FROM '.table('suppliers').' WHERE status="active" ORDER BY company_name LIMIT 400')->fetchAll();$contracts=$pdo->query('SELECT c.*,s.company_name FROM '.table('supplier_contracts').' c LEFT JOIN '.table('suppliers').' s ON s.id=c.supplier_id ORDER BY c.created_at DESC LIMIT 100')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){try{$action=(string)($_POST['action']??'contract');if($action==='milestone'){$pdo->prepare('INSERT INTO '.table('supplier_contract_milestones').' (supplier_contract_id,milestone_title,due_date,amount,status,notes) VALUES (?,?,?,?, "pending", ?)')->execute([(int)$_POST['contract_id'],trim((string)$_POST['milestone_title']),trim((string)$_POST['due_date'])?:null,max(0,(float)$_POST['amount']),trim((string)$_POST['notes'])]);flash('success','Contract milestone added.');}else{$num=nextScopedDocumentNumber($pdo,'supplier_contract',setting('supplier_contract_prefix','SCON'),operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('supplier_contracts').' (contract_number,supplier_id,contract_title,contract_type,start_date,end_date,contract_value,status,renewal_notice_days,notes) VALUES (?,?,?,?,?,?,?,"active",?,?)')->execute([$num,(int)$_POST['supplier_id'],trim((string)$_POST['contract_title']),trim((string)$_POST['contract_type']),trim((string)$_POST['start_date'])?:null,trim((string)$_POST['end_date'])?:null,max(0,(float)$_POST['contract_value']),max(0,(int)$_POST['renewal_notice_days']),trim((string)$_POST['notes'])]);flash('success','Supplier contract created.');}}catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'supplier-contracts']);flash('error',$e->getMessage());}redirect(ADMIN_URL.'/erp/supplier-contracts.php');}
$milestones=$pdo->query('SELECT m.*,c.contract_number FROM '.table('supplier_contract_milestones').' m LEFT JOIN '.table('supplier_contracts').' c ON c.id=m.supplier_contract_id ORDER BY m.created_at DESC LIMIT 150')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Contract Lifecycle</div><h2 class="h4 mb-1">Supplier Contracts</h2><p class="text-secondary mb-0">Track supplier agreements, renewal notice windows, milestones, and contract values.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Contract</h2><select class="form-select mb-2" name="supplier_id"><?php foreach($suppliers as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['supplier_code'].' · '.$s['company_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="contract_title" placeholder="Contract title"><input class="form-control mb-2" name="contract_type" placeholder="Supply / Service / Framework"><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="start_date"></div><div class="col-6"><input class="form-control" type="date" name="end_date"></div></div><input class="form-control my-2" type="number" step="0.01" name="contract_value" placeholder="Contract value"><input class="form-control mb-2" type="number" name="renewal_notice_days" value="30"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Contract</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="milestone"><h2 class="h5 mb-3">Add Milestone</h2><select class="form-select mb-2" name="contract_id"><?php foreach($contracts as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['contract_number'].' · '.$c['contract_title']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="milestone_title" placeholder="Milestone"><input class="form-control mb-2" type="date" name="due_date"><input class="form-control mb-2" type="number" step="0.01" name="amount" placeholder="Amount"><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Add Milestone</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Contracts</h2><table class="table"><thead><tr><th>Contract</th><th>Supplier</th><th>Dates</th><th>Value</th><th>Status</th></tr></thead><tbody><?php foreach($contracts as $c): ?><tr><td><strong><?php echo esc($c['contract_number']); ?></strong><div class="small text-secondary"><?php echo esc($c['contract_title']); ?></div></td><td><?php echo esc($c['company_name']); ?></td><td><?php echo esc($c['start_date'].' → '.$c['end_date']); ?></td><td><?php echo money($c['contract_value']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Milestones</h2><table class="table"><thead><tr><th>Contract</th><th>Milestone</th><th>Due</th><th>Amount</th><th>Status</th></tr></thead><tbody><?php foreach($milestones as $m): ?><tr><td><?php echo esc($m['contract_number']); ?></td><td><?php echo esc($m['milestone_title']); ?></td><td><?php echo esc($m['due_date']); ?></td><td><?php echo money($m['amount']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($m['status'])); ?>"><?php echo esc($m['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>